#nullable enable // autogenerated

namespace MVZ2.Metas
{
    public class AlmanacVariableReferenceLocal : AlmanacVariableReference
    {
        public string localName;

        public AlmanacVariableReferenceLocal(string localName)
        {
            this.localName = localName;
        }
        public override object? GetVariableValue(AlmanacVariableContext context)
        {
            var variable = context.currentAlmanacEntry.GetLocalVariable(localName);
            if (variable == null)
                return null;
            return variable.GetVariableValue(context);
        }
    }
}
